-- math: Place Value to Thousands
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Place Value to Thousands", "body": "Each digit's value depends on its place: ones, tens, hundreds, thousands. The same digit is worth more the farther left it sits."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the value of the digit 9 in 3694? (Write just the number, e.g. 300)\n\nThe answer is \"90\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the value of the digit 5 in 9651? (Write just the number, e.g. 300)\n\nThe answer is \"50\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the value of the digit 9 in 5295? (Write just the number, e.g. 300)\n\nThe answer is \"90\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the value of the digit 6 in 1086? (Write just the number, e.g. 300)\n\nThe answer is 6."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the value of the digit 7 in 7288? (Write just the number, e.g. 300)\n\nThe answer is 7000."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the value of the digit 6 in 2865? (Write just the number, e.g. 300)\n\nThe answer is 60."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Place Value to Thousands! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$place-value-to-thousands$tl$ and t.grade_level = 3);

-- math: Rounding to 10 and 100
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Rounding to 10 and 100", "body": "To round, look at the digit to the right of the place you're rounding to. 5 or more rounds up; less than 5 rounds down."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Round 37 to the nearest ten.\n\nThe answer is \"40\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Round 999 to the nearest hundred.\n\nThe answer is \"1000\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Round 51 to the nearest ten.\n\nThe answer is \"50\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Round 85 to the nearest ten.\n\nThe answer is 90."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Round 927 to the nearest hundred.\n\nThe answer is 900."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Round 38 to the nearest ten.\n\nThe answer is 40."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Rounding to 10 and 100! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$rounding-to-10-and-100$tl$ and t.grade_level = 3);

-- math: Add & Subtract within 1000
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Add & Subtract within 1000", "body": "Line up numbers by place value and add or subtract one column at a time, regrouping when a column is 10 or more."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Add: 469 + 291 = ?\n\nThe answer is \"760\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Subtract: 675 - 182 = ?\n\nThe answer is \"493\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Add: 281 + 271 = ?\n\nThe answer is \"552\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Add: 331 + 48 = ?\n\nThe answer is 379."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Subtract: 614 - 287 = ?\n\nThe answer is 327."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Add: 751 + 587 = ?\n\nThe answer is 1338."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Add & Subtract within 1000! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$add-and-subtract-within-1000$tl$ and t.grade_level = 3);

-- math: Multiplication Facts
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Multiplication Facts", "body": "Multiplication is fast adding of equal groups. Knowing your facts to 10 x 10 by heart makes bigger math much easier."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Multiply: 4 x 4 = ?\n\nThe answer is \"16\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Multiply: 2 x 3 = ?\n\nThe answer is \"6\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Multiply: 8 x 7 = ?\n\nThe answer is \"56\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Multiply: 6 x 4 = ?\n\nThe answer is 24."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Multiply: 5 x 8 = ?\n\nThe answer is 40."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Multiply: 5 x 2 = ?\n\nThe answer is 10."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Multiplication Facts! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$multiplication-facts$tl$ and t.grade_level = 3);

-- math: Division Facts
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Division Facts", "body": "Division splits a number into equal groups. It is the opposite of multiplication: if 3 x 4 = 12, then 12 / 4 = 3."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Divide: 49 / 7 = ?\n\nThe answer is \"7\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Divide: 27 / 3 = ?\n\nThe answer is \"9\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Divide: 50 / 5 = ?\n\nThe answer is \"10\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Divide: 48 / 8 = ?\n\nThe answer is 6."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Divide: 10 / 2 = ?\n\nThe answer is 5."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Divide: 42 / 6 = ?\n\nThe answer is 7."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Division Facts! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$division-facts$tl$ and t.grade_level = 3);

-- math: Equal Groups
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Equal Groups", "body": "When you have several equal groups, multiply the number of groups by how many are in each group to find the total."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  There are 8 groups with 7 in each group. How many in all?\n\nThe answer is \"56\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  36 things are shared equally into 6 groups. How many in each group?\n\nThe answer is \"6\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  There are 5 groups with 4 in each group. How many in all?\n\nThe answer is \"20\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  There are 5 groups with 8 in each group. How many in all?\n\nThe answer is 40."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  24 things are shared equally into 3 groups. How many in each group?\n\nThe answer is 8."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  There are 3 groups with 6 in each group. How many in all?\n\nThe answer is 18."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Equal Groups! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$equal-groups$tl$ and t.grade_level = 3);

-- math: Understanding Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Understanding Fractions", "body": "A fraction names equal parts of a whole. The bottom number tells how many equal parts there are; 1/4 means 1 of 4 equal parts."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The fraction 1/8 means 1 out of how many equal parts?\n\nThe answer is \"8\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which fraction is bigger: 1/3 or 1/6?\n\nThe answer is \"1/3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The fraction 1/4 means 1 out of how many equal parts?\n\nThe answer is \"4\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is bigger: 1/2 or 1/8?", "choices": [{"id": "a", "label": "1/8"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "Neither"}, {"id": "d", "label": "1/2"}], "answer": "d", "explanation": "Yes! The answer is \"1/2\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is bigger: 1/3 or 1/2?", "choices": [{"id": "a", "label": "1/2"}, {"id": "b", "label": "1/3"}, {"id": "c", "label": "They are equal"}, {"id": "d", "label": "Neither"}], "answer": "a", "explanation": "Yes! The answer is \"1/2\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is bigger: 1/6 or 1/2?", "choices": [{"id": "a", "label": "1/6"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "Neither"}, {"id": "d", "label": "1/2"}], "answer": "d", "explanation": "Yes! The answer is \"1/2\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Understanding Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$unit-fractions$tl$ and t.grade_level = 3);

-- math: Comparing Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Fractions", "body": "When fractions have the same bottom number (denominator), the one with the bigger top number (numerator) is greater."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which fraction is greater: 3/4 or 1/4?\n\nThe answer is \"3/4\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which fraction is greater: 1/8 or 2/8?\n\nThe answer is \"2/8\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which fraction is greater: 4/6 or 1/6?\n\nThe answer is \"4/6\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 2/8 or 1/8?", "choices": [{"id": "a", "label": "1/8"}, {"id": "b", "label": "2/8"}, {"id": "c", "label": "They are equal"}, {"id": "d", "label": "3/8"}], "answer": "b", "explanation": "Yes! The answer is \"2/8\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 1/5 or 2/5?", "choices": [{"id": "a", "label": "2/5"}, {"id": "b", "label": "1/5"}, {"id": "c", "label": "They are equal"}, {"id": "d", "label": "3/5"}], "answer": "a", "explanation": "Yes! The answer is \"2/5\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which fraction is greater: 2/4 or 1/4?", "choices": [{"id": "a", "label": "1/4"}, {"id": "b", "label": "They are equal"}, {"id": "c", "label": "2/4"}, {"id": "d", "label": "3/4"}], "answer": "c", "explanation": "Yes! The answer is \"2/4\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$comparing-fractions$tl$ and t.grade_level = 3);

-- math: Area of Rectangles
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Area of Rectangles", "body": "Area is the space inside a shape, measured in square units. For a rectangle, multiply length by width."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A rectangle is 12 units long and 7 units wide. What is its area in square units?\n\nThe answer is \"84\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A rectangle is 11 units long and 3 units wide. What is its area in square units?\n\nThe answer is \"33\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A rectangle is 3 units long and 12 units wide. What is its area in square units?\n\nThe answer is \"36\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A rectangle is 4 units long and 7 units wide. What is its area in square units?\n\nThe answer is 28."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A rectangle is 7 units long and 12 units wide. What is its area in square units?\n\nThe answer is 84."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A rectangle is 3 units long and 6 units wide. What is its area in square units?\n\nThe answer is 18."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Area of Rectangles! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$area-of-rectangles$tl$ and t.grade_level = 3);

-- math: Perimeter of Rectangles
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Perimeter of Rectangles", "body": "Perimeter is the distance all the way around a shape. Add up the lengths of all the sides."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A rectangle is 15 units long and 5 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is \"40\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A rectangle is 3 units long and 13 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is \"32\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A rectangle is 5 units long and 5 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is \"20\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A rectangle is 7 units long and 5 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is 24."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A rectangle is 7 units long and 12 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is 38."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A rectangle is 4 units long and 11 units wide. What is its perimeter (add up all 4 sides)?\n\nThe answer is 30."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Perimeter of Rectangles! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$perimeter-of-rectangles$tl$ and t.grade_level = 3);

-- science: Forces & Motion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Forces & Motion", "body": "A force is a push or a pull. Forces can make things start, stop, speed up, slow down, or change direction."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A push or a pull is called a:\n\nThe answer is \"force\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  To make a still ball start rolling, you must:\n\nThe answer is \"push or pull it\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Kicking a soccer ball is an example of a:\n\nThe answer is \"push\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Opening a drawer toward you is an example of a:", "choices": [{"id": "a", "label": "pull"}, {"id": "b", "label": "push"}, {"id": "c", "label": "spin"}, {"id": "d", "label": "drop"}], "answer": "a", "explanation": "Yes! The answer is \"pull\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The bigger the force on an object, usually the:", "choices": [{"id": "a", "label": "less it moves"}, {"id": "b", "label": "colder it gets"}, {"id": "c", "label": "quieter it gets"}, {"id": "d", "label": "more its motion changes"}], "answer": "d", "explanation": "Yes! The answer is \"more its motion changes\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which makes a wagon speed up more?", "choices": [{"id": "a", "label": "a gentle tap"}, {"id": "b", "label": "no push"}, {"id": "c", "label": "a hard push"}, {"id": "d", "label": "a whisper"}], "answer": "c", "explanation": "Yes! The answer is \"a hard push\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Forces & Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$forces-and-motion$tl$ and t.grade_level = 3);

-- science: Balanced & Unbalanced Forces
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Balanced & Unbalanced Forces", "body": "Balanced forces are equal and opposite, so motion stays the same. Unbalanced forces change how something moves."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  When two forces are equal and opposite, they are:\n\nThe answer is \"balanced\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  In a tug-of-war where nobody moves, the forces are:\n\nThe answer is \"balanced\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Balanced forces on a still object make it:\n\nThe answer is \"stay still\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Unbalanced forces cause an object's motion to:", "choices": [{"id": "a", "label": "stay exactly the same"}, {"id": "b", "label": "disappear"}, {"id": "c", "label": "change"}, {"id": "d", "label": "freeze"}], "answer": "c", "explanation": "Yes! The answer is \"change\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A book resting on a table has forces that are:", "choices": [{"id": "a", "label": "unbalanced"}, {"id": "b", "label": "balanced"}, {"id": "c", "label": "spinning"}, {"id": "d", "label": "missing"}], "answer": "b", "explanation": "Yes! The answer is \"balanced\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "If one team in tug-of-war pulls harder, the forces become:", "choices": [{"id": "a", "label": "balanced"}, {"id": "b", "label": "equal"}, {"id": "c", "label": "unbalanced"}, {"id": "d", "label": "silent"}], "answer": "c", "explanation": "Yes! The answer is \"unbalanced\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Balanced & Unbalanced Forces! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$balanced-and-unbalanced-forces$tl$ and t.grade_level = 3);

-- science: Patterns of Motion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Patterns of Motion", "body": "Many motions repeat in patterns, like a swing or a clock. When motion has a pattern, we can predict what comes next."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A swing going back and forth shows a motion that is:\n\nThe answer is \"repeating (a pattern)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Because motion follows patterns, we can:\n\nThe answer is \"predict where it goes next\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A bouncing ball usually bounces:\n\nThe answer is \"a little lower each time\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The hands of a clock move in a pattern that:", "choices": [{"id": "a", "label": "repeats every hour"}, {"id": "b", "label": "never repeats"}, {"id": "c", "label": "is random"}, {"id": "d", "label": "stops at noon"}], "answer": "a", "explanation": "Yes! The answer is \"repeats every hour\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A merry-go-round spins in a motion that is:", "choices": [{"id": "a", "label": "straight only"}, {"id": "b", "label": "round and round (circular)"}, {"id": "c", "label": "zig-zag"}, {"id": "d", "label": "backward only"}], "answer": "b", "explanation": "Yes! The answer is \"round and round (circular)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A pendulum swings in a pattern, so its next swing is:", "choices": [{"id": "a", "label": "impossible to know"}, {"id": "b", "label": "easy to predict"}, {"id": "c", "label": "always different"}, {"id": "d", "label": "invisible"}], "answer": "b", "explanation": "Yes! The answer is \"easy to predict\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Patterns of Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$patterns-of-motion$tl$ and t.grade_level = 3);

-- science: Magnets & Forces
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Magnets & Forces", "body": "Magnets pull on iron and can push or pull other magnets without touching. Opposite poles attract; like poles repel."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A magnet can pull objects made of:\n\nThe answer is \"iron\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Magnets can push or pull without:\n\nThe answer is \"touching\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Two north poles brought together will:\n\nThe answer is \"push apart (repel)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A north pole and a south pole will:", "choices": [{"id": "a", "label": "pull together (attract)"}, {"id": "b", "label": "repel"}, {"id": "c", "label": "vanish"}, {"id": "d", "label": "spin"}], "answer": "a", "explanation": "Yes! The answer is \"pull together (attract)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which object would a magnet attract?", "choices": [{"id": "a", "label": "a steel paperclip"}, {"id": "b", "label": "a rubber band"}, {"id": "c", "label": "a paper cup"}, {"id": "d", "label": "a wooden block"}], "answer": "a", "explanation": "Yes! The answer is \"a steel paperclip\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A magnet's force is strongest at its:", "choices": [{"id": "a", "label": "middle"}, {"id": "b", "label": "color"}, {"id": "c", "label": "weight"}, {"id": "d", "label": "poles"}], "answer": "d", "explanation": "Yes! The answer is \"poles\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Magnets & Forces! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$magnets-and-forces$tl$ and t.grade_level = 3);

-- science: Life Cycles
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Life Cycles", "body": "Living things are born, grow, reproduce, and die. Different plants and animals go through different life-cycle stages."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The stages a living thing goes through is called its:\n\nThe answer is \"life cycle\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A butterfly starts its life as an:\n\nThe answer is \"egg\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  After hatching, a butterfly is a:\n\nThe answer is \"caterpillar (larva)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A caterpillar forms a chrysalis and becomes a:", "choices": [{"id": "a", "label": "beetle"}, {"id": "b", "label": "butterfly"}, {"id": "c", "label": "fish"}, {"id": "d", "label": "flower"}], "answer": "b", "explanation": "Yes! The answer is \"butterfly\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A frog begins life as an egg, then becomes a:", "choices": [{"id": "a", "label": "tadpole"}, {"id": "b", "label": "caterpillar"}, {"id": "c", "label": "chick"}, {"id": "d", "label": "puppy"}], "answer": "a", "explanation": "Yes! The answer is \"tadpole\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A plant's life cycle often starts with a:", "choices": [{"id": "a", "label": "seed"}, {"id": "b", "label": "flower first"}, {"id": "c", "label": "fruit first"}, {"id": "d", "label": "leaf first"}], "answer": "a", "explanation": "Yes! The answer is \"seed\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Life Cycles! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
