  where s.slug = $tl$science$tl$ and t.slug = $tl$life-cycles$tl$ and t.grade_level = 3);

-- science: Traits & Inheritance
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Traits & Inheritance", "body": "Offspring inherit traits from their parents, which is why young plants and animals resemble the ones they came from."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A feature passed from parents to offspring is a:\n\nThe answer is \"trait\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Puppies often look like their:\n\nThe answer is \"parents\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Eye color in people is mostly a:\n\nThe answer is \"inherited trait\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Offspring inherit traits from:", "choices": [{"id": "a", "label": "the weather"}, {"id": "b", "label": "their friends"}, {"id": "c", "label": "their parents"}, {"id": "d", "label": "the soil"}], "answer": "c", "explanation": "Yes! The answer is \"their parents\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A tall plant often has seeds that grow into plants that are:", "choices": [{"id": "a", "label": "tall too"}, {"id": "b", "label": "always short"}, {"id": "c", "label": "made of metal"}, {"id": "d", "label": "blue"}], "answer": "a", "explanation": "Yes! The answer is \"tall too\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is an inherited trait of a dog?", "choices": [{"id": "a", "label": "a leash it wears"}, {"id": "b", "label": "its name"}, {"id": "c", "label": "fur color"}, {"id": "d", "label": "its collar"}], "answer": "c", "explanation": "Yes! The answer is \"fur color\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Traits & Inheritance! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
