  where s.slug = $tl$science$tl$ and t.slug = $tl$traits-and-inheritance$tl$ and t.grade_level = 3);

-- science: Variation of Traits
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Variation of Traits", "body": "Individuals of the same kind are not all identical. Some differences are inherited and some are shaped by the environment."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Differences in traits among the same kind of animal are called:\n\nThe answer is \"variation\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Some dogs of the same breed have slightly different:\n\nThe answer is \"sizes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Variation means individuals of one kind are:\n\nThe answer is \"not all exactly alike\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Some traits are influenced by the environment, like a plant getting:", "choices": [{"id": "a", "label": "a new name"}, {"id": "b", "label": "a fence"}, {"id": "c", "label": "more sunlight and growing taller"}, {"id": "d", "label": "a sticker"}], "answer": "c", "explanation": "Yes! The answer is \"more sunlight and growing taller\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Two sunflower seeds from the same plant may grow to be:", "choices": [{"id": "a", "label": "different heights"}, {"id": "b", "label": "the same exact height always"}, {"id": "c", "label": "animals"}, {"id": "d", "label": "rocks"}], "answer": "a", "explanation": "Yes! The answer is \"different heights\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A trait that can change with food and care is:", "choices": [{"id": "a", "label": "its species"}, {"id": "b", "label": "an animal's weight"}, {"id": "c", "label": "its number of eyes"}, {"id": "d", "label": "its skeleton count"}], "answer": "b", "explanation": "Yes! The answer is \"an animal's weight\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Variation of Traits! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
