  where s.slug = $tl$science$tl$ and t.slug = $tl$variation-of-traits$tl$ and t.grade_level = 3);

-- science: Adaptations & Survival
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Adaptations & Survival", "body": "An adaptation is a body part or behavior that helps a living thing survive in its environment."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A body part or behavior that helps an animal survive is an:\n\nThe answer is \"adaptation\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A polar bear's thick fur is an adaptation for:\n\nThe answer is \"staying warm in the cold\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A cactus stores water in its thick stem to survive in the:\n\nThe answer is \"desert\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Camouflage helps an animal:", "choices": [{"id": "a", "label": "glow at night"}, {"id": "b", "label": "fly higher"}, {"id": "c", "label": "hide from predators"}, {"id": "d", "label": "swim faster only"}], "answer": "c", "explanation": "Yes! The answer is \"hide from predators\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A duck's webbed feet are an adaptation for:", "choices": [{"id": "a", "label": "swimming"}, {"id": "b", "label": "climbing trees"}, {"id": "c", "label": "digging"}, {"id": "d", "label": "flying high"}], "answer": "a", "explanation": "Yes! The answer is \"swimming\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Sharp claws help a hawk to:", "choices": [{"id": "a", "label": "stay warm"}, {"id": "b", "label": "see color"}, {"id": "c", "label": "catch prey"}, {"id": "d", "label": "sing"}], "answer": "c", "explanation": "Yes! The answer is \"catch prey\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Adaptations & Survival! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
