  where s.slug = $tl$science$tl$ and t.slug = $tl$adaptations-and-survival$tl$ and t.grade_level = 3);

-- science: Habitats & Change
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Habitats & Change", "body": "A habitat gives living things food, water, and shelter. When habitats change, living things must move, adapt, or struggle."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The place where a plant or animal naturally lives is its:\n\nThe answer is \"habitat\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A habitat provides an animal with food, water, and:\n\nThe answer is \"shelter\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  If a pond dries up, the fish living there will:\n\nThe answer is \"lose their habitat\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Cutting down a forest can cause animals to:", "choices": [{"id": "a", "label": "gain new planets"}, {"id": "b", "label": "stop needing food"}, {"id": "c", "label": "lose their homes"}, {"id": "d", "label": "turn to stone"}], "answer": "c", "explanation": "Yes! The answer is \"lose their homes\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which animal best fits a desert habitat?", "choices": [{"id": "a", "label": "a polar bear"}, {"id": "b", "label": "a whale"}, {"id": "c", "label": "a penguin"}, {"id": "d", "label": "a lizard"}], "answer": "d", "explanation": "Yes! The answer is \"a lizard\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When the environment changes, some animals:", "choices": [{"id": "a", "label": "move to a new area"}, {"id": "b", "label": "instantly adapt perfectly"}, {"id": "c", "label": "disappear by magic"}, {"id": "d", "label": "grow gills always"}], "answer": "a", "explanation": "Yes! The answer is \"move to a new area\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Habitats & Change! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
