  where s.slug = $tl$science$tl$ and t.slug = $tl$habitats-and-environment-change$tl$ and t.grade_level = 3);

-- science: Weather & Climate
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Weather & Climate", "body": "Weather is the day-to-day state of the air. Climate is the usual weather of a place measured over many years."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The day-to-day state of the air (sunny, rainy, windy) is:\n\nThe answer is \"weather\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The usual weather of a place over many years is its:\n\nThe answer is \"climate\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A tool that measures temperature is a:\n\nThe answer is \"thermometer\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Rain, snow, and hail are all kinds of:", "choices": [{"id": "a", "label": "climate"}, {"id": "b", "label": "precipitation"}, {"id": "c", "label": "wind"}, {"id": "d", "label": "sunshine"}], "answer": "b", "explanation": "Yes! The answer is \"precipitation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A place that is hot and dry most of the year has a:", "choices": [{"id": "a", "label": "polar climate"}, {"id": "b", "label": "desert climate"}, {"id": "c", "label": "rainy climate"}, {"id": "d", "label": "ocean of ice"}], "answer": "b", "explanation": "Yes! The answer is \"desert climate\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Scientists who study and predict weather are:", "choices": [{"id": "a", "label": "dentists"}, {"id": "b", "label": "meteorologists"}, {"id": "c", "label": "pilots"}, {"id": "d", "label": "chefs"}], "answer": "b", "explanation": "Yes! The answer is \"meteorologists\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Weather & Climate! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$weather-and-climate$tl$ and t.grade_level = 3);

-- reading: Finding the Main Idea
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Finding the Main Idea", "body": "The main idea is what a passage is mostly about. Ask yourself the one big thing the author wants you to know."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Sam's dog Biscuit can do tricks. He can sit, roll over, and shake hands.\" What is the main idea?\n\nThe answer is \"Biscuit can do tricks.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Rain helps the Earth. It fills rivers, waters plants, and gives animals water to drink.\" The main idea is that rain:\n\nThe answer is \"helps living things\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Maria cleaned her room. She made her bed, picked up toys, and put away books.\" What is the main idea?\n\nThe answer is \"Maria cleaned her room.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Bees are busy. They fly to flowers, gather nectar, and make honey.\" The passage is mostly about:", "choices": [{"id": "a", "label": "the color of flowers"}, {"id": "b", "label": "how to bake"}, {"id": "c", "label": "rainy days"}, {"id": "d", "label": "what bees do"}], "answer": "d", "explanation": "Yes! The answer is \"what bees do\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Our class went to the farm. We saw cows, fed goats, and picked apples.\" The main idea is that the class:", "choices": [{"id": "a", "label": "ate lunch"}, {"id": "b", "label": "stayed home"}, {"id": "c", "label": "visited a farm"}, {"id": "d", "label": "read a book"}], "answer": "c", "explanation": "Yes! The answer is \"visited a farm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Winter is fun. You can build snowmen, go sledding, and drink hot cocoa.\" The main idea is that winter:", "choices": [{"id": "a", "label": "is short"}, {"id": "b", "label": "is fun"}, {"id": "c", "label": "is warm"}, {"id": "d", "label": "has no snow"}], "answer": "b", "explanation": "Yes! The answer is \"is fun\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Finding the Main Idea! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$main-idea$tl$ and t.grade_level = 3);

-- reading: Key Details
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Key Details", "body": "Key details are the facts in a text that answer who, what, where, when, why, and how."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Lily has a red kite. She flies it in the park on windy days.\" Where does Lily fly her kite?\n\nThe answer is \"in the park\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"The picnic had sandwiches, juice, and grapes.\" Which food was at the picnic?\n\nThe answer is \"grapes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Max woke up early to walk his dog before school.\" When did Max walk his dog?\n\nThe answer is \"before school\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The turtle moved slowly across the warm sand.\" How did the turtle move?", "choices": [{"id": "a", "label": "slowly"}, {"id": "b", "label": "quickly"}, {"id": "c", "label": "backward"}, {"id": "d", "label": "by flying"}], "answer": "a", "explanation": "Yes! The answer is \"slowly\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Ana painted a picture of a blue whale.\" What did Ana paint?", "choices": [{"id": "a", "label": "a red car"}, {"id": "b", "label": "a blue whale"}, {"id": "c", "label": "a green tree"}, {"id": "d", "label": "a yellow sun"}], "answer": "b", "explanation": "Yes! The answer is \"a blue whale\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"It rained all morning, so we played games inside.\" Why did they play inside?", "choices": [{"id": "a", "label": "it was sunny"}, {"id": "b", "label": "it was night"}, {"id": "c", "label": "school was closed"}, {"id": "d", "label": "because it rained"}], "answer": "d", "explanation": "Yes! The answer is \"because it rained\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Key Details! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$key-details$tl$ and t.grade_level = 3);

-- reading: Sequence of Events
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Sequence of Events", "body": "Sequence is the order things happen. Words like first, next, then, and last help you keep track."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"First Mia got dressed. Next she ate breakfast. Then she went to school.\" What did Mia do FIRST?\n\nThe answer is \"got dressed\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Jack planted a seed, watered it, and watched it grow.\" What did Jack do LAST?\n\nThe answer is \"watched it grow\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"We packed a bag, drove to the beach, and built a sandcastle.\" What happened SECOND?\n\nThe answer is \"drove to the beach\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The bell rang, the kids lined up, and they walked inside.\" What happened FIRST?", "choices": [{"id": "a", "label": "the bell rang"}, {"id": "b", "label": "kids walked inside"}, {"id": "c", "label": "kids lined up"}, {"id": "d", "label": "class started"}], "answer": "a", "explanation": "Yes! The answer is \"the bell rang\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Dad mixed the batter, poured it in a pan, and baked a cake.\" What did Dad do right after mixing?", "choices": [{"id": "a", "label": "poured it in a pan"}, {"id": "b", "label": "baked the cake"}, {"id": "c", "label": "ate the cake"}, {"id": "d", "label": "washed dishes"}], "answer": "a", "explanation": "Yes! The answer is \"poured it in a pan\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She tied her shoes, grabbed her ball, and ran outside.\" What did she do LAST?", "choices": [{"id": "a", "label": "tied her shoes"}, {"id": "b", "label": "ran outside"}, {"id": "c", "label": "grabbed her ball"}, {"id": "d", "label": "sat down"}], "answer": "b", "explanation": "Yes! The answer is \"ran outside\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Sequence of Events! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$story-sequence$tl$ and t.grade_level = 3);

-- reading: Cause & Effect
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Cause & Effect", "body": "A cause is why something happens; the effect is what happens. Words like because and so connect them."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"It started to rain, so we ran inside.\" Why did they run inside?\n\nThe answer is \"because it rained\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Ed forgot his umbrella, so he got wet.\" What was the effect?\n\nThe answer is \"he got wet\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The plant got sunlight and water, so it grew.\" Why did the plant grow?\n\nThe answer is \"it got sunlight and water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She practiced every day, so she got better at piano.\" What caused her to improve?", "choices": [{"id": "a", "label": "she quit"}, {"id": "b", "label": "she practiced every day"}, {"id": "c", "label": "she slept"}, {"id": "d", "label": "it was easy"}], "answer": "b", "explanation": "Yes! The answer is \"she practiced every day\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The ice cream melted because it was hot outside.\" Why did it melt?", "choices": [{"id": "a", "label": "it was frozen"}, {"id": "b", "label": "it was hot outside"}, {"id": "c", "label": "it was night"}, {"id": "d", "label": "it was tiny"}], "answer": "b", "explanation": "Yes! The answer is \"it was hot outside\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"He dropped the cup, so it broke.\" What was the effect of dropping the cup?", "choices": [{"id": "a", "label": "it floated"}, {"id": "b", "label": "it broke"}, {"id": "c", "label": "it grew"}, {"id": "d", "label": "nothing happened"}], "answer": "b", "explanation": "Yes! The answer is \"it broke\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Cause & Effect! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
