-- reading: Vocabulary in Context
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Vocabulary in Context", "body": "Use the words around an unknown word as clues to figure out what it means."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The tiny ant was so small I could barely see it.\" What does \"tiny\" mean?\n\nThe answer is \"very small\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"She was joyful and smiled all day.\" What does \"joyful\" mean?\n\nThe answer is \"very happy\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The soup was hot, so he let it cool down.\" What does \"hot\" mean here?\n\nThe answer is \"very warm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The path was narrow, so only one person could pass.\" What does \"narrow\" mean?", "choices": [{"id": "a", "label": "very tall"}, {"id": "b", "label": "bright"}, {"id": "c", "label": "heavy"}, {"id": "d", "label": "not wide"}], "answer": "d", "explanation": "Yes! The answer is \"not wide\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"He was exhausted after running and fell asleep fast.\" What does \"exhausted\" mean?", "choices": [{"id": "a", "label": "excited"}, {"id": "b", "label": "hungry"}, {"id": "c", "label": "very tired"}, {"id": "d", "label": "cold"}], "answer": "c", "explanation": "Yes! The answer is \"very tired\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The huge elephant was the biggest animal there.\" What does \"huge\" mean?", "choices": [{"id": "a", "label": "very big"}, {"id": "b", "label": "very small"}, {"id": "c", "label": "very quiet"}, {"id": "d", "label": "very fast"}], "answer": "a", "explanation": "Yes! The answer is \"very big\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Vocabulary in Context! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$context-clues$tl$ and t.grade_level = 3);

-- reading: Making Predictions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Making Predictions", "body": "A prediction is a smart guess about what will happen next, based on clues in the text."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Dark clouds gathered and the wind grew strong.\" What will probably happen next?\n\nThe answer is \"It will rain.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Tom put on his swimsuit and grabbed a towel.\" What will Tom probably do?\n\nThe answer is \"go swimming\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The cake is in the oven and the timer is almost done.\" What will happen soon?\n\nThe answer is \"The cake will be ready.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Mia yawned and rubbed her eyes at bedtime.\" What will Mia probably do?", "choices": [{"id": "a", "label": "fall asleep"}, {"id": "b", "label": "run a race"}, {"id": "c", "label": "eat lunch"}, {"id": "d", "label": "go to school"}], "answer": "a", "explanation": "Yes! The answer is \"fall asleep\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"He filled the watering can and walked to the garden.\" What will he probably do?", "choices": [{"id": "a", "label": "wash the car"}, {"id": "b", "label": "cook dinner"}, {"id": "c", "label": "fly a kite"}, {"id": "d", "label": "water the plants"}], "answer": "d", "explanation": "Yes! The answer is \"water the plants\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The team is winning with one minute left.\" What will probably happen?", "choices": [{"id": "a", "label": "The game starts over."}, {"id": "b", "label": "Everyone goes home first."}, {"id": "c", "label": "They lose for sure."}, {"id": "d", "label": "The team will likely win."}], "answer": "d", "explanation": "Yes! The answer is \"The team will likely win.\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Making Predictions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$making-predictions$tl$ and t.grade_level = 3);

-- reading: Characters & Setting
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Characters & Setting", "body": "Characters are who a story is about. The setting is where and when the story happens."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"In the busy city, Ravi waited for the train.\" Where does this happen (setting)?\n\nThe answer is \"in the city\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Kind Mrs. Lee helped the lost kitten find its way home.\" Who is the character?\n\nThe answer is \"Mrs. Lee\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"It was a snowy night in the quiet village.\" What is the setting?\n\nThe answer is \"a snowy village at night\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Brave Captain Mara sailed her ship through the storm.\" Who is the main character?", "choices": [{"id": "a", "label": "Captain Mara"}, {"id": "b", "label": "the storm"}, {"id": "c", "label": "the ship's flag"}, {"id": "d", "label": "the ocean"}], "answer": "a", "explanation": "Yes! The answer is \"Captain Mara\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"At the farm, the rooster crowed at sunrise.\" Where does the story take place?", "choices": [{"id": "a", "label": "in a city"}, {"id": "b", "label": "on the Moon"}, {"id": "c", "label": "on a farm"}, {"id": "d", "label": "in a cave"}], "answer": "c", "explanation": "Yes! The answer is \"on a farm\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Curious Leo loved to ask questions about everything.\" What word describes Leo?", "choices": [{"id": "a", "label": "lazy"}, {"id": "b", "label": "curious"}, {"id": "c", "label": "mean"}, {"id": "d", "label": "sleepy"}], "answer": "b", "explanation": "Yes! The answer is \"curious\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Characters & Setting! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$character-and-setting$tl$ and t.grade_level = 3);

-- reading: Fact vs. Opinion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Fact vs. Opinion", "body": "A fact can be proven true. An opinion tells what someone feels and can't be proven. Words like best signal opinions."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which is a FACT?\n\nThe answer is \"A dog has four legs.\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which is an OPINION?\n\nThe answer is \"Summer is the best season.\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which is a FACT?\n\nThe answer is \"The sun gives us light.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which is an OPINION?", "choices": [{"id": "a", "label": "Pizza has cheese."}, {"id": "b", "label": "A triangle has 3 sides."}, {"id": "c", "label": "Birds lay eggs."}, {"id": "d", "label": "Pizza tastes amazing."}], "answer": "d", "explanation": "Yes! The answer is \"Pizza tastes amazing.\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Our school has 200 students.\" This is a:", "choices": [{"id": "a", "label": "opinion"}, {"id": "b", "label": "question"}, {"id": "c", "label": "fact"}, {"id": "d", "label": "story"}], "answer": "c", "explanation": "Yes! The answer is \"fact\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"Reading is more fun than TV.\" This is an:", "choices": [{"id": "a", "label": "opinion"}, {"id": "b", "label": "fact"}, {"id": "c", "label": "rule"}, {"id": "d", "label": "number"}], "answer": "a", "explanation": "Yes! The answer is \"opinion\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Fact vs. Opinion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$fact-and-opinion$tl$ and t.grade_level = 3);

-- reading: Compare & Contrast
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Compare & Contrast", "body": "Comparing shows how things are alike; contrasting shows how they differ. 'Both' signals alike; 'but' and 'unlike' signal different."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"A cat and a dog are both pets, but a cat purrs and a dog barks.\" How are they ALIKE?\n\nThe answer is \"both are pets\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Apples are crunchy, but bananas are soft.\" This shows a:\n\nThe answer is \"difference\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Both a bike and a car have wheels.\" The word that signals they are alike is:\n\nThe answer is \"both\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Summer is hot, but winter is cold.\" This compares the seasons by:", "choices": [{"id": "a", "label": "color"}, {"id": "b", "label": "size"}, {"id": "c", "label": "name"}, {"id": "d", "label": "temperature"}], "answer": "d", "explanation": "Yes! The answer is \"temperature\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Unlike a fish, a frog can live on land.\" The word \"unlike\" signals a:", "choices": [{"id": "a", "label": "similarity"}, {"id": "b", "label": "sequence"}, {"id": "c", "label": "difference"}, {"id": "d", "label": "cause"}], "answer": "c", "explanation": "Yes! The answer is \"difference\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"A pencil and a crayon are both used to draw, but a pencil can be erased.\" How are they DIFFERENT?", "choices": [{"id": "a", "label": "both draw"}, {"id": "b", "label": "both are tools"}, {"id": "c", "label": "a pencil can be erased"}, {"id": "d", "label": "both are long"}], "answer": "c", "explanation": "Yes! The answer is \"a pencil can be erased\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Compare & Contrast! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$compare-and-contrast$tl$ and t.grade_level = 3);

-- reading: Synonyms & Antonyms
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Synonyms & Antonyms", "body": "Synonyms are words that mean almost the same thing. Antonyms mean the opposite."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word means almost the same as \"happy\"?\n\nThe answer is \"glad\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is the OPPOSITE of \"big\"?\n\nThe answer is \"small\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A synonym for \"fast\" is:\n\nThe answer is \"quick\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The opposite of \"hot\" is:", "choices": [{"id": "a", "label": "cold"}, {"id": "b", "label": "warm"}, {"id": "c", "label": "boiling"}, {"id": "d", "label": "sunny"}], "answer": "a", "explanation": "Yes! The answer is \"cold\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A synonym for \"happy\" is:", "choices": [{"id": "a", "label": "grumpy"}, {"id": "b", "label": "upset"}, {"id": "c", "label": "mad"}, {"id": "d", "label": "cheerful"}], "answer": "d", "explanation": "Yes! The answer is \"cheerful\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The opposite of \"up\" is:", "choices": [{"id": "a", "label": "high"}, {"id": "b", "label": "above"}, {"id": "c", "label": "top"}, {"id": "d", "label": "down"}], "answer": "d", "explanation": "Yes! The answer is \"down\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Synonyms & Antonyms! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
