update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Nouns", "body": "A noun names a person, place, thing, or idea. Common nouns are general; proper nouns name a specific one."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"kitchen\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"sister\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is a noun (a person, place, or thing)?\n\nThe answer is \"mountain\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "river"}, {"id": "b", "label": "whisper"}, {"id": "c", "label": "march"}, {"id": "d", "label": "paint"}], "answer": "a", "explanation": "Yes! The answer is \"river\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "bounce"}, {"id": "b", "label": "puppy"}, {"id": "c", "label": "brave"}, {"id": "d", "label": "march"}], "answer": "b", "explanation": "Yes! The answer is \"puppy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is a noun (a person, place, or thing)?", "choices": [{"id": "a", "label": "forest"}, {"id": "b", "label": "scribble"}, {"id": "c", "label": "shiny"}, {"id": "d", "label": "cheerful"}], "answer": "a", "explanation": "Yes! The answer is \"forest\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Nouns! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
