update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Action Verbs", "body": "A verb shows action. Action verbs tell what the subject does, like run, jump, or think."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Which word is an action verb (something you can do)?\n\nThe answer is \"explore\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Which word is an action verb (something you can do)?\n\nThe answer is \"wander\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which word is an action verb (something you can do)?\n\nThe answer is \"shout\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "stormy"}, {"id": "b", "label": "build"}, {"id": "c", "label": "sister"}, {"id": "d", "label": "slippery"}], "answer": "b", "explanation": "Yes! The answer is \"build\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "enormous"}, {"id": "b", "label": "jump"}, {"id": "c", "label": "brave"}, {"id": "d", "label": "blanket"}], "answer": "b", "explanation": "Yes! The answer is \"jump\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which word is an action verb (something you can do)?", "choices": [{"id": "a", "label": "enormous"}, {"id": "b", "label": "curious"}, {"id": "c", "label": "bounce"}, {"id": "d", "label": "garden"}], "answer": "c", "explanation": "Yes! The answer is \"bounce\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Action Verbs! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
