-- writing: Subject-Verb Agreement
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Subject-Verb Agreement", "body": "The verb must match the subject. A singular subject usually takes a verb ending in -s."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Choose the correct verb: \"The puppy ____ every day.\"\n\nThe answer is \"wags\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Choose the correct verb: \"The student ____ every day.\"\n\nThe answer is \"reads\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Choose the correct verb: \"The dog ____ every day.\"\n\nThe answer is \"barks\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The singer ____ every day.\"", "choices": [{"id": "a", "label": "performs"}, {"id": "b", "label": "perform"}, {"id": "c", "label": "performsed"}, {"id": "d", "label": "performsing"}], "answer": "a", "explanation": "Yes! The answer is \"performs\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The flower ____ every day.\"", "choices": [{"id": "a", "label": "grow"}, {"id": "b", "label": "growsed"}, {"id": "c", "label": "growsing"}, {"id": "d", "label": "grows"}], "answer": "d", "explanation": "Yes! The answer is \"grows\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Choose the correct verb: \"The bird ____ every day.\"", "choices": [{"id": "a", "label": "sings"}, {"id": "b", "label": "sing"}, {"id": "c", "label": "singsed"}, {"id": "d", "label": "singsing"}], "answer": "a", "explanation": "Yes! The answer is \"sings\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Subject-Verb Agreement! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
